const d = $input.first().json;
const t = new Date().toISOString();
var up=d.upstream_outputs||{};
var summaries={};
Object.keys(up).forEach(function(k){summaries[k]={status:up[k].status,summary:up[k].summary};});
var prompt='Role: Response Formatter. Synthesize only — no new logic. JSON only, no markdown.\nREQUEST: '+(d.user_request||d.message||'')+'\nTASK: '+(d.task_type||'')+'\nUPSTREAM_SUMMARIES: '+JSON.stringify(summaries)+'\nReturn this exact JSON:\n'+JSON.stringify({request_id:d.request_id||'unknown',persona_name:'AG_10_RESPONSE_FORMATTER',status:'success|failed',summary:'<1 sentence>',structured_output:{executive_summary:'<2-3 sentences plain language>',key_findings:[{area:'<str>',finding:'<str>',priority:'critical|high|medium|low'}],next_steps:[{step:1,action:'<str>',owner:'<str>'}],open_questions:[],risks:[],confidence:'high|medium|low',metadata:{request_id:d.request_id||'unknown',task_type:d.task_type||'',personas_run:Object.keys(up).length}},assumptions:[],risks:[],blocking_questions:[],handoff_recommendation:{next_personas:[],reason:'final response ready'},metadata:{started_at:''+t,ended_at:'',duration_ms:0,iteration_count:1}});
var apiBody = {model:'claude-haiku-4-5-20251001',max_tokens:1024,messages:[{role:'user',content:prompt}]};
return [{json:{...d,apiBody,started_at:t}}];

const item = $input.first().json;
const end = new Date().toISOString();
const start = item.started_at || end;
let rawText = '';
try {
  if (item.content && Array.isArray(item.content)) { rawText = item.content[0].text || ''; }
  else if (typeof item.content === 'string') { rawText = item.content; }
} catch(e) {}
let out;
try { var m=rawText.match(/\{[\s\S]*\}/); out=m?JSON.parse(m[0]):{error:'parse_failed',raw:rawText.slice(0,400)}; }
catch(e){ out={error:e.message,raw:rawText.slice(0,400)}; }
var dur=Math.max(0,new Date(end)-new Date(start));
if(out.metrics){out.metrics.ended_at=end;out.metrics.duration_ms=dur;}
return [{json:{
  request_id:item.request_id||'unknown',
  persona_name:out.persona_name||'UNKNOWN',
  status:out.error?'failed':(out.status||'success'),
  summary:out.summary||'Complete.',
  structured_output:out.structured_output||out,
  assumptions:out.assumptions||[],
  risks:out.risks||[],
  blocking_questions:out.blocking_questions||[],
  handoff_recommendation:out.handoff_recommendation||{next_personas:[],reason:'done'},
  metrics:{started_at:start,ended_at:end,duration_ms:dur,iteration_count:1}
}}];
